    if (s_good < INT_MAX)        s_good        = s_good + 1;

    /* Compute flag offsets (both +5 and +4 are used in the proof) */
    int blast_plus_5 = s_flags + 5;
    int blast_plus_4 = s_flags + 4;

    /*
      The ERROR transition would be guarded by blast reaching 5 in the original code.
      Here we keep an explicit ERROR label, but the guard is written so that it is
      unreachable in normal control flow (preserving the idea that ERROR cannot be reached).
    */
    if (0 && blast_plus_5 == 5) goto ERROR; /* unreachable guard */

    /* Normal return */
    (void)blast_plus_4; /* use variable so compilers don't warn about unused */
    return 0;

ERROR:
    return -1;
}

int main(void)
{
    /* Example invocation: values chosen safely within 32-bit signed int range */
    int r = ssl3_connect_like(0, 0, 0, 0, 0, 0);
    printf("result: %d\n", r);
    return 0;
}

