#include <stdio.h>
#include <stdlib.h>
#include <time.h>

int ssl3_connect(void) {
    /* All arithmetic is on unsigned types; signed ints only receive constants,
       nondeterministic values (rand()), or results of bitwise XOR. */
    unsigned int u1 = 100u;
    unsigned int u2 = 200u;
    unsigned long ul = (unsigned long)u1 + (unsigned long)u2; /* unsigned addition */
    unsigned int u3 = u1 * 3u;                               /* unsigned multiplication */
    unsigned int u4 = (u3 + u2) ^ 0xFFu;                     /* unsigned add and XOR */

    int s1 = 0;           /* assigned a constant */
    s1 = s1 ^ 42;         /* bitwise XOR on signed int (no overflow) */

    int s2 = rand();      /* nondeterministic value (fits in signed int) */
    s2 = s2 ^ s1;         /* XOR of signed ints */

    if ((ul & 1u) == 0u) {
        u4 += 1u;         /* unsigned increment */
    }

    unsigned int count = 0u;
    while (count < 10u) { /* loop uses unsigned comparison and increment */
        count++;
        u4 ^= count;      /* unsigned XOR */
    }

    /* Ensure returned int fits in signed 32-bit range by masking,
       using unsigned mask so no signed arithmetic occurs. */
    return (int)(u4 & 0x7FFFFFFFu);
}

int main(void) {
    srand((unsigned int)time(NULL));
    int result = ssl3_connect();
    printf("ssl3_connect returned %d\n", result);
    return 0;
}

#include <stdlib.h>
#include <stdint.h>

int ssl3_connect(void) {
    /* unsigned arithmetic only */
    unsigned int ui = (unsigned int)rand();
    unsigned long ul = (unsigned long)rand();

    unsigned int ui_sum = ui + (unsigned int)100U;
    unsigned long ul_sub = ul - (unsigned long)50U;
    unsigned long ul_neg = 0UL - ul_sub; /* unary minus effect on unsigned */

    /* signed int used only for assignment, comparison, and bitwise XOR */
    int si = rand();        /* nondeterministic assignment */
    si = si ^ 0x1234;       /* bitwise XOR on signed int (no arithmetic) */

    if (si != 0) {          /* comparison only */
        unsigned long res = (unsigned long)ui_sum + ul_neg;
        (void)res;
        return 1;
    } else {
        unsigned int res2 = ui_sum - (unsigned int)1U;
        (void)res2;
        return 0;
    }
}

int main(void) {
    return ssl3_connect();
}

