int nondet_int(void) {
    /* Produce a pseudo-random int by combining two rand() values with XOR.
       This avoids signed arithmetic operations. */
    int r1 = rand();
    int r2 = rand();
    return r1 ^ r2;
}

int ssl3_connect(void) {
    int a = 0;
    int b = nondet_int();
    int c = a ^ b; /* only bitwise XOR on signed ints */
    return c;
}

