    return 0;
}

#include <stdio.h>
#include <stdint.h>
#include <inttypes.h>

int32_t applyHanoi(int n, int32_t counter) {
    if (n <= 0) return counter;
    int32_t inner = applyHanoi(n - 1, counter + 1);
    return applyHanoi(n - 1, inner);
}

int main(void) {
    int32_t n;
    if (scanf("%" SCNd32, &n) != 1) return 1;
    if (n < 1 || n > 31) return 0;
    int32_t result = applyHanoi((int)n, 0);
    printf("%" PRId32 "\n", result);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int hanoi(int n) {
    if (n == 0) return 0;
    return 2 * hanoi(n - 1) + 1;
}

int applyHanoiCount(int n) {
    if (n == 0) return 0;
    return 1 + 2 * applyHanoiCount(n - 1);
}

int main(void) {
    int n;
    if (scanf("%d", &n) != 1) return 1;
    if (n < 1 || n > 31) {
        fprintf(stderr, "n out of range (must be between 1 and 31)\n");
        return 1;
    }
    int moves = hanoi(n);
    int count = applyHanoiCount(n);
    printf("%d %d\n", moves, count);
    return 0;
}

#include <stdio.h>

int hanoi(int n) {
    if (n == 0) return 0;
    if (n == 1) return 1;
    return 2 * hanoi(n - 1) + 1;
}

int counter;

void applyHanoi(int n) {
    if (n == 0) return;
    counter++;
    applyHanoi(n - 1);
    applyHanoi(n - 1);
}

int main(void) {
    int n;
    if (scanf("%d", &n) != 1) return 1;
    printf("%d\n", hanoi(n));
    counter = 0;
    applyHanoi(n);
    printf("%d\n", counter);
    return 0;
}

