#include <stdint.h>
#include <stdio.h>

int main(void) {
    int32_t i = 0;
    int32_t j = 3;
    int32_t c = 0;

    while (1) {
        while (j < 12) {
            c = c + 1;
            j = j + 1;
            /* use expressions like j-1 and (j-1)+2 to mirror verified operations */
            int32_t tmp1 = j - 1;
            int32_t tmp2 = tmp1 + 2;
            (void)tmp1;
            (void)tmp2;
        }
        if (i < 10) {
            int32_t ni = i + 1;
            i = ni;
            j = 3;
        } else {
            break;
        }
    }

    printf("%d %d %d\n", (int)i, (int)j, (int)c);
    return 0;
}

#include <stdio.h>
