int32_t f91(int32_t n) {
    if (n > 100) return n - 10;
    else return 91;
}

int main(void) {
    int32_t x;
    if (scanf("%" SCNd32, &x) != 1) return 1;
    int32_t res = f91(x);
    if (res == 91 || (x > 101 && res == x - 10)) {
        printf("OK\n");
        return 0;
    } else {
        printf("FAIL\n");
        return 2;
    }
}

